import{_ as t,o as h,c as i,ae as o}from"./chunks/framework.BeVX27ge.js";const p=JSON.parse('{"title":"Quản lý Prompt","description":"","frontmatter":{},"headers":[],"relativePath":"admin-prompts.md","filePath":"admin-prompts.md"}'),a={name:"admin-prompts.md"};function r(e,n,l,c,s,g){return h(),i("div",null,[...n[0]||(n[0]=[o('<h1 id="quan-ly-prompt" tabindex="-1">Quản lý Prompt <a class="header-anchor" href="#quan-ly-prompt" aria-label="Permalink to &quot;Quản lý Prompt&quot;">​</a></h1><blockquote><p>Kiểm soát hành vi của AI, tạo trải nghiệm thực hành sát với thực tế nhất.</p></blockquote><h2 id="tong-quan" tabindex="-1">Tổng quan <a class="header-anchor" href="#tong-quan" aria-label="Permalink to &quot;Tổng quan&quot;">​</a></h2><p>Prompt là chỉ lệnh cốt lõi điều khiển hành vi của AI. Tính năng này giúp quản trị viên điều chỉnh cách AI phản hồi, tiêu chí đánh giá, và quy tắc tạo vai, nhằm đáp ứng mục tiêu đào tạo.</p><blockquote><p>Chỉ dành cho Quản trị viên có quyền Quản lý Prompt.</p></blockquote><h2 id="cau-truc-trang" tabindex="-1">Cấu trúc Trang <a class="header-anchor" href="#cau-truc-trang" aria-label="Permalink to &quot;Cấu trúc Trang&quot;">​</a></h2><ul><li><strong>Thanh Tiêu đề</strong>: Chọn Công ty/Phòng ban, Chọn Phiên bản, và các nút thao tác.</li><li><strong>Danh sách Thẻ Prompt</strong>: Hiển thị tất cả Prompt trong phiên bản hiện tại.</li><li><strong>Bảng Chỉnh sửa</strong>: Khung trượt bên phải hiển thị giao diện chỉnh sửa.</li></ul><hr><h2 id="chi-tiet-the-prompt" tabindex="-1">Chi tiết Thẻ Prompt <a class="header-anchor" href="#chi-tiet-the-prompt" aria-label="Permalink to &quot;Chi tiết Thẻ Prompt&quot;">​</a></h2><p>Mỗi thẻ hiển thị:</p><ul><li><strong>Tên</strong>: Tên nhận dạng duy nhất</li><li><strong>Mô tả</strong>: Tóm tắt chức năng</li><li><strong>Thẻ Phân loại</strong>: Danh mục của Prompt (như Character, Judge, System...)</li><li><strong>Nhãn &quot;Đang sử dụng&quot;</strong>: Nếu Prompt đã được phát hành</li><li><strong>Chỉnh sửa / Xóa</strong>: Các nút thao tác</li></ul><hr><h2 id="chinh-sua-prompt" tabindex="-1">Chỉnh sửa Prompt <a class="header-anchor" href="#chinh-sua-prompt" aria-label="Permalink to &quot;Chỉnh sửa Prompt&quot;">​</a></h2><p>Nhấp <strong>&quot;Chỉnh sửa&quot;</strong> để mở bảng điều khiển bên phải.</p><h3 id="truong-thong-tin" tabindex="-1">Trường thông tin <a class="header-anchor" href="#truong-thong-tin" aria-label="Permalink to &quot;Trường thông tin&quot;">​</a></h3><ul><li><strong>Tên</strong>: Nhận dạng duy nhất (Bắt buộc).</li><li><strong>Danh mục</strong>: Danh sách phân loại.</li><li><strong>Mô tả</strong>: Chức năng của Prompt.</li><li><strong>Nội dung Prompt</strong>: Trình soạn thảo văn bản lớn để nhập chỉ lệnh.</li></ul><h3 id="he-thong-bien" tabindex="-1">Hệ thống Biến <a class="header-anchor" href="#he-thong-bien" aria-label="Permalink to &quot;Hệ thống Biến&quot;">​</a></h3><p>Sử dụng dấu ngoặc nhọn <code>{...}</code> để chèn biến. VD: <code>{question}</code>, <code>{character_detail}</code>, <code>{conversation_history}</code>, <code>{stage_description}</code>.</p><hr><h2 id="quan-ly-phien-ban" tabindex="-1">Quản lý Phiên bản <a class="header-anchor" href="#quan-ly-phien-ban" aria-label="Permalink to &quot;Quản lý Phiên bản&quot;">​</a></h2><p>Tính năng này giúp bạn chỉnh sửa và kiểm thử Prompt mà không ảnh hưởng đến phiên bản hiện tại.</p><ul><li><strong>Thêm Phiên bản</strong>: Sao chép Prompt từ phiên bản hiện tại sang phiên bản mới.</li><li><strong>Phát hành</strong>: Đặt phiên bản làm phiên bản Đang sử dụng.</li><li>Lưu ý: Chỉ phiên bản &quot;Phát hành&quot; mới được áp dụng cho các bài tập mới. Các bài tập đang diễn ra sẽ sử dụng phiên bản cũ.</li></ul><hr><h2 id="loi-khuyen" tabindex="-1">Lời khuyên <a class="header-anchor" href="#loi-khuyen" aria-label="Permalink to &quot;Lời khuyên&quot;">​</a></h2><ol><li><strong>Luôn tạo phiên bản mới</strong> thay vì sửa đổi trực tiếp phiên bản Đang sử dụng.</li><li><strong>Kiểm thử kỹ lưỡng</strong> trước khi Phát hành.</li></ol>',25)])])}const d=t(a,[["render",r]]);export{p as __pageData,d as default};
